3	export function logger(req: Request, res: Response, next: NextFunction): void {
4	  const start = Date.now();
5	  res.on("finish", () => {
6	    const duration = Date.now() - start;
7	    console.log(`${req.method} ${req.path} ${res.statusCode} - ${duration}ms`);
8	  });
9	  next();
10	}
