  if (!comment) {
    res.status(404).json({ error: "Comment not found" });
    return;
  }
  res.json(comment);
});

// POST /posts/:postId/comments - create a comment on a post
router.post("/posts/:postId/comments", (req, res) => {
  const postId = parseInt(req.params.postId, 10);
  const post = posts.find((p) => p.id === postId);
  if (!post) {
    res.status(404).json({ error: "Post not found" });
    return;
  }
  const { body, userId } = req.body;
  if (!body) {
    res.status(400).json({ error: "body is required" });
    return;
  }
  const newComment: Comment = {
    id: nextId(comments),
    postId,
    userId: userId || 1,
    body,
    createdAt: new Date().toISOString(),
  };
  comments.push(newComment);
  res.status(201).json(newComment);
});

// PUT /comments/:id - update a comment
router.put("/comments/:id", (req, res) => {
  const id = parseInt(req.params.id, 10);
  const index = comments.findIndex((c) => c.id === id);
  if (index === -1) {
    res.status(404).json({ error: "Comment not found" });
    return;
  }
  const { body } = req.body;
  if (body) comments[index].body = body;
  res.json(comments[index]);
});

// DELETE /comments/:id - delete a comment
router.delete("/comments/:id", (req, res) => {
  const id = parseInt(req.params.id, 10);
  const index = comments.findIndex((c) => c.id === id);
  if (index === -1) {
    res.status(404).json({ error: "Comment not found" });
    return;
  }
  const deleted = comments.splice(index, 1);
  res.json(deleted[0]);
});

export { router as commentsRouter };
```

**Route Patterns:**
- GET comments for post: `router.get("/posts/:postId/comments", ...)` - uses `req.params.postId`
- GET single comment: `router.get("/comments/:id", ...)` - uses `req.params.id`
- POST new comment: `router.post("/posts/:postId/comments", ...)` - extracts `req.body.body` and `req.body.userId`
- PUT update: `router.put("/comments/:id", ...)` - partial update
- DELETE: `router.delete("/comments/:id", ...)` - removes comment

**Nested Resource Pattern:**
- Comments are nested under posts: `/posts/:postId/comments`
- Requires post existence validation before operations

---

### **5. Data Types (`src/types.ts`)**

```typescript
export interface User {
  id: number;
  username: string;
  email: string;
  password: string;
}

export interface Post {
  id: number;
  title: string;
  content: string;
  userId: number;
  createdAt: string;
}

export interface Comment {
  id: number;
  postId: number;
  userId: number;
  body: string;
  createdAt: string;
}
```

---

### **6. Database (`src/db.ts`)**

In-memory database with three collections:
- **users**: 3 test users with plaintext passwords (marked as security issue in comments)
- **posts**: 4 posts linked to users via `userId`
- **comments**: 5 comments linked to posts via `postId` and users via `userId`
- **Helper**: `nextId()` function generates sequential IDs by finding max and adding 1

**Note:** Passwords stored in plaintext - flagged in code comments as needing security fix.

---

### **Key Observations for JWT Auth Implementation**

1. **User Data Available**: `users` array exists with `id`, `username`, `email`, and `password` fields - ready for auth integration
2. **Current Security**: No authentication currently - all endpoints accessible without credentials
3. **Post/Comment Ownership**: Both Post and Comment have `userId` fields - perfect for authorization checks
4. **Response Pattern**: Consistent `res.json()` and `res.status().json()` - can add token to responses
5. **Request Data Handling**: Using `req.body` for login credentials, `req.params` for IDs - standard pattern
6. **Middleware Available**: Logger middleware demonstrates middleware pattern - auth middleware can follow same pattern
7. **User Defaults**: Current handlers default `userId` to 1 when not provided - will need JWT subject claim instead
8. **No Database Abstraction**: Direct in-memory array operations - can wrap with auth checks
9. **Error Response Format**: Consistent `{ error: "message" }` structure for errors

This is a well-structured Express API ready for JWT authentication to be added with minimal refactoring.

